					lines.push(`  ✓ ${sub.label}${subDuration ? ` (${subDuration})` : ""}`);
				} else {
					lines.push(`  ${SPINNER_FRAMES[_spinnerIndex % SPINNER_FRAMES.length]} ${sub.label}...`);
